import test from 'node:test';
import assert from 'node:assert/strict';

import { buildDailyReport } from '../src/report-service.mjs';

test('a multi-metric report distinguishes missing data from measured zero end to end', () => {
  const report = buildDailyReport(
    [
      { sensorId: 'flow-a', metric: 'flow', value: null, unit: 'L/s' },
      { sensorId: 'flow-b', metric: 'flow', value: 0, unit: 'L/s' },
      { sensorId: 'flow-c', metric: 'flow', value: '6', unit: 'L/s' },
      { sensorId: 'line-a', metric: 'pressure', value: '2', unit: 'bar' },
      { sensorId: 'line-b', metric: 'pressure', value: null, unit: 'bar' }
    ],
    ['flow', 'pressure']
  );

  assert.deepEqual(report, {
    flow: {
      metric: 'flow',
      count: 2,
      minimum: 0,
      maximum: 6,
      average: 3
    },
    pressure: {
      metric: 'pressure',
      count: 1,
      minimum: 2,
      maximum: 2,
      average: 2
    }
  });
});
